const e=["行政处罚决定书","检查笔录","现场勘查笔录","辨认笔录","搜查笔录","行政处罚告知笔录","调解协议书","扣押决定书","指认笔录","结案报告"],s={行政处罚决定书:"需填写：当事人信息（姓名、性别、年龄、身份证号、住址）、案发日期与地点、违法事实描述、证据列表、处罚依据（具体法条）、处罚内容（拘留天数/罚款金额）、告知日期、处罚决定日期、权利告知、办案民警及单位。注意：告知日期必须在处罚决定日期之前。",检查笔录:'需填写：公安机关名称、检查起止时间（精确到分钟）、检查地点（留空则默认为"公安机关名称+检查室"）、被检查人姓名、违法性质、检查人姓名及工作单位、见证人基本情况（姓名、性别、身份证件种类及号码）、有无发现涉案物品、有无发现损伤。检查地点、事由和目的、过程和结果由系统自动生成。',现场勘查笔录:"需填写：案件编号、勘查起止时间、勘查地点、天气及照明条件、勘查人员、记录人、见证人≥2人、现场保护情况、现场方位及中心现场描述、提取痕迹物证情况、现场照片数量、现场图信息、录像信息、办案民警及单位。",辨认笔录:'需填写：公安机关名称、辨认起止时间（精确到分钟）、辨认地点（留空则默认为"公安机关名称+询问室"）、办案人员姓名及单位、辨认人姓名及证件号及身份（被害人/证人/涉案人员）、见证人姓名及住址、辨认对象（如"N组十二张不同男性正面彩色免冠照片组"）、案发日期、案发地点、案件性质/案由、案件背景及辨认准备过程、辨认结果（每行一条，如"辨认照片X组中（X）号照片的人就是XX"）、记录人。辨认目的、辨认操作描述、辨认结论、确认声明由系统自动生成。',搜查笔录:"需填写：案件编号、搜查起止时间、搜查地点、搜查人员≥2人、记录人、被搜查人及见证人、搜查证编号、搜查范围、搜查过程记录、查获物品及存放位置、扣押物品清单、搜查中损坏物品情况、被搜查人意见、办案民警及单位。",行政处罚告知笔录:"需填写：案件编号、告知时间、告知地点、告知人、被告知人及身份证号、违法事实摘要、拟处罚内容、处罚依据（法条）、权利告知、被告知人陈述申辩内容、是否提出陈述申辩（是/否）、是否要求听证（是/否）、办案民警及单位。",调解协议书:"需填写：案件编号、调解时间、调解地点、主持人、记录人、甲方（姓名、身份证号、住址、电话）、乙方（姓名、身份证号、住址、电话）、纠纷事实、调解协议内容（须具体可执行）、赔偿金额、履行期限、履行方式、自愿调解声明、办案民警及单位。",扣押决定书:"需填写：案件编号、扣押日期、扣押地点、物品持有人及身份证号、扣押依据（法条）、扣押物品清单（逐项列明名称、数量、特征）、物品总数、保管地点、保管人、权利告知、持有人意见、处理决定备注、办案民警及单位。",指认笔录:"需填写：公安机关名称、指认起止时间（精确到分钟）、指认地点（案发现场，默认为案发地点）、侦查人员姓名及单位、指认人姓名及性别及户籍地址、见证人姓名及单位/住址、案发日期、案发地点、案发经过简述、案件性质/案由、指认确认内容、指认对象、记录人。指认目的、指认地点和指认确认内容可由系统自动生成。",结案报告:"需填写：案件编号、案件性质、违法/犯罪嫌疑人姓名及身份证号、发案时间与地点、立案日期、侦查/调查经过、证据情况综述、案件事实认定结论、法律适用说明、处理意见、呈请结案日期、办案民警及单位、审批意见。"},i=["illegal_fact","case_brief","case_fact","fact_description","dispute_fact","inspection_process","inspection_findings","search_process","investigation_summary","case_summary","scene_description","identification_process","case_conclusion","evidence_list","evidence_summary","qa_content","rights_statement","seized_items_list","mediation_agreement","illegal_fact_summary","handling_suggestion","law_application","items_seized","items_found","evidence_collected","case_background","identification_results"],t="行政处罚决定书";export{t as D,s as F,i as T,e as a};
